// MainActivity.kt
package com.example.sharehandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.ImageView
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class MainActivity : AppCompatActivity() {

    private lateinit var textViewSharedContent: TextView
    private lateinit var imageViewSharedImage: ImageView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        textViewSharedContent = findViewById(R.id.textViewSharedContent)
        imageViewSharedImage = findViewById(R.id.imageViewSharedImage)

        handleIncomingIntent(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        intent?.let { handleIncomingIntent(it) }
    }

    private fun handleIncomingIntent(intent: Intent) {
        when (intent.action) {
            Intent.ACTION_SEND -> {
                if (intent.type?.startsWith("text/") == true) {
                    handleSharedText(intent)
                } else if (intent.type?.startsWith("image/") == true) {
                    handleSharedImage(intent)
                }
            }
            Intent.ACTION_SEND_MULTIPLE -> {
                if (intent.type?.startsWith("image/") == true) {
                    handleSharedMultipleImages(intent)
                }
            }
        }
    }

    private fun handleSharedText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        if (sharedText != null) {
            processSharedText(sharedText)
        } else {
            Toast.makeText(this, "No text content found", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleSharedImage(intent: Intent) {
        val imageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
        if (imageUri != null) {
            processSharedImage(imageUri)
        } else {
            Toast.makeText(this, "No image found", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleSharedMultipleImages(intent: Intent) {
        val imageUris = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
        if (imageUris != null && imageUris.isNotEmpty()) {
            processSharedImage(imageUris[0])
            Toast.makeText(this, "Received ${imageUris.size} images. Showing first one.", Toast.LENGTH_SHORT).show()
        } else {
            Toast.makeText(this, "No images found", Toast.LENGTH_SHORT).show()
        }
    }

    private fun processSharedText(text: String) {
        val urlPattern = Regex("https?://[^\\s]+")
        val urls = urlPattern.findAll(text).map { it.value }.toList()

        if (urls.isNotEmpty()) {
            val displayText = buildString {
                append("Found ${urls.size} URL(s):\n\n")
                urls.forEachIndexed { index, url ->
                    append("${index + 1}. $url\n")
                }
                append("\nFull text:\n$text")
            }
            textViewSharedContent.text = displayText
            imageViewSharedImage.setImageDrawable(null)
            Toast.makeText(this, "Extracted ${urls.size} URL(s)", Toast.LENGTH_SHORT).show()
        } else {
            textViewSharedContent.text = "Shared text:\n$text"
            imageViewSharedImage.setImageDrawable(null)
            Toast.makeText(this, "Text received (no URLs found)", Toast.LENGTH_SHORT).show()
        }
    }

    private fun processSharedImage(imageUri: Uri) {
        try {
            imageViewSharedImage.setImageURI(imageUri)
            textViewSharedContent.text = "Image URI:\n$imageUri"
            Toast.makeText(this, "Image received successfully", Toast.LENGTH_SHORT).show()
        } catch (e: Exception) {
            Toast.makeText(this, "Error loading image: ${e.message}", Toast.LENGTH_SHORT).show()
        }
    }
}